import "../libraries/FeeDistributorLib.sol";
import "../libraries/LibDiamond.sol";
import "../utilities/Modifiers.sol";
import "../identity/IdentityStorage.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title TransferFacet
 * @dev A Diamond facet for routing payments with fee distribution, security protections, and compliance rules.
 */
contract TransferFacet is Modifiers, ReentrancyGuard {
    using SafeERC20 for IERC20;

    /// @notice Maximum number of transactions allowed in batch operations to prevent DOS attacks
    uint256 public constant MAX_BATCH_SIZE = 50;

    /// @notice Minimum fee threshold to prevent dust accumulation (0.0001% in basis points)
    uint256 public constant MIN_FEE_THRESHOLD = 1; // 1 basis point = 0.01%

    // Routing function identifiers for different routing functions
    bytes32 public constant ROUTE_PAYMENT_BASIC = keccak256("ROUTE_PAYMENT_BASIC");
    bytes32 public constant ROUTE_PAYMENT_ANY_TOKEN = keccak256("ROUTE_PAYMENT_ANY_TOKEN");
    bytes32 public constant ROUTE_PAYMENT_TOKEN_ONLY = keccak256("ROUTE_PAYMENT_TOKEN_ONLY");
    bytes32 public constant BATCH_ROUTE_PAYMENTS = keccak256("BATCH_ROUTE_PAYMENTS");

    // Storage for function compliance requirements - maps function ID to required claim topics
    mapping(bytes32 => uint256[]) private functionClaimRequirements;
    mapping(bytes32 => bool) private functionComplianceActive;
    mapping(bytes32 => string) private functionComplianceDescriptions;

    // Events
    event RoutedPayment(
        address indexed sender,
        address indexed recipient,
        address indexed token,
        uint256 originalAmount,
        uint256 adjustedAmount,
        address[] feeReceivers,
        uint256[] feeAmounts
    );

    event BatchPaymentCompleted(
        address indexed sender,
        uint256 totalTransactions,
        uint256 totalVolume
    );

    event FunctionComplianceSet(
        bytes32 indexed functionId,
        uint256[] requiredClaimTopics,
        string description
    );

    event FunctionComplianceDeactivated(bytes32 indexed functionId);
    event FunctionComplianceReactivated(bytes32 indexed functionId);

    /**
     * @notice Restricts function access to trusted issuers only
     * @dev Uses the same trusted issuer system as IdentityRegistryFacet
     */
    modifier isTrustedIssuer() {
        IdentitySystemStorage.IdentitySystem storage _storage = IdentitySystemStorage.diamondStorage();
        require(IdentitySystemStorage.isTrustedIssuer(_storage, msg.sender), "TransferFacet: Not trusted issuer");
        _;
    }

    /**
     * @notice Restricts function access to owner or trusted issuers
     * @dev Allows both contract owner and trusted issuers to manage compliance rules
     */
    modifier onlyOwnerOrTrustedIssuer() {
        IdentitySystemStorage.IdentitySystem storage _storage = IdentitySystemStorage.diamondStorage();
        require(
            msg.sender == LibDiamond.diamondStorage().contractOwner || IdentitySystemStorage.isTrustedIssuer(_storage, msg.sender),
            "TransferFacet: Not owner or trusted issuer"
        );
        _;
    }

    /**
     * @notice Modifier to enforce claim topic requirements for a specific routing function
     * @param functionId The routing function identifier
     * @param recipient The recipient address (kept for interface compatibility)
     */
    modifier checkClaimTopicCompliance(bytes32 functionId, address recipient) {
        if (functionComplianceActive[functionId] && functionClaimRequirements[functionId].length > 0) {
            require(
                _validateUserClaimTopics(msg.sender, functionClaimRequirements[functionId]),
                "TransferFacet: Sender missing required claim topics"
            );
            // Note: Only sender compliance is checked. Recipient compliance not required.
        }
        _;
    }

    /**
     * @notice Sets claim topic requirements for a specific routing function
     * @dev Can be called by owner or trusted issuers. Uses centralized claim topics.
     * @param functionId The identifier of the routing function
     * @param requiredClaimTopics Array of claim topics required for this function
     * @param description Human-readable description of the compliance requirement
     */
    function setFunctionClaimRequirements(
        bytes32 functionId,
        uint256[] calldata requiredClaimTopics,
        string calldata description
    ) external onlyOwnerOrTrustedIssuer {
        require(requiredClaimTopics.length > 0, "TransferFacet: At least one claim topic required");

        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();

        // Validate that all claim topics exist in the centralized claim topics registry
        for (uint256 i = 0; i < requiredClaimTopics.length; i++) {
            require(IdentitySystemStorage.hasClaimTopic(ds, requiredClaimTopics[i]), "TransferFacet: Claim topic does not exist");
        }

        // Store the requirements
        functionClaimRequirements[functionId] = requiredClaimTopics;
        functionComplianceActive[functionId] = true;
        functionComplianceDescriptions[functionId] = description;

        emit FunctionComplianceSet(functionId, requiredClaimTopics, description);
    }

    /**
     * @notice Deactivates claim topic requirements for a specific routing function
     * @dev Can be called by owner or trusted issuers
     * @param functionId The identifier of the routing function
     */
    function deactivateFunctionCompliance(bytes32 functionId) external onlyOwnerOrTrustedIssuer {
        require(functionComplianceActive[functionId], "TransferFacet: Function compliance not active");
        functionComplianceActive[functionId] = false;
        emit FunctionComplianceDeactivated(functionId);
    }

    /**
     * @notice Reactivates claim topic requirements for a specific routing function
     * @dev Can be called by owner or trusted issuers
     * @param functionId The identifier of the routing function
     */
    function reactivateFunctionCompliance(bytes32 functionId) external onlyOwnerOrTrustedIssuer {
        require(!functionComplianceActive[functionId], "TransferFacet: Function compliance already active");
        require(functionClaimRequirements[functionId].length > 0, "TransferFacet: No claim requirements set");
        functionComplianceActive[functionId] = true;
        emit FunctionComplianceReactivated(functionId);
    }

