     * @notice Gets claim topic requirements for a specific routing function
     * @param functionId The identifier of the routing function
     * @return requiredClaimTopics Array of required claim topics
     * @return isActive Whether the compliance requirement is active
     * @return description Description of the compliance requirement
     */
    function getFunctionClaimRequirements(bytes32 functionId) 
        external 
        view 
        returns (
            uint256[] memory requiredClaimTopics,
            bool isActive,
            string memory description
        ) 
    {
        return (
            functionClaimRequirements[functionId], 
            functionComplianceActive[functionId], 
            functionComplianceDescriptions[functionId]
        );
    }

    /**
     * @notice Gets all available routing function identifiers
     * @return functionIds Array of all routing function identifiers
     */
    function getRoutingFunctionIds() external pure returns (bytes32[] memory functionIds) {
        functionIds = new bytes32[](4);
        functionIds[0] = ROUTE_PAYMENT_BASIC;
        functionIds[1] = ROUTE_PAYMENT_ANY_TOKEN;
        functionIds[2] = ROUTE_PAYMENT_TOKEN_ONLY;
        functionIds[3] = BATCH_ROUTE_PAYMENTS;
        return functionIds;
    }

    /**
     * @notice Gets all available claim topics from the centralized registry
     * @return claimTopics Array of all registered claim topics
     */
    function getAvailableClaimTopics() external view returns (uint256[] memory claimTopics) {
        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();
        return IdentitySystemStorage.getClaimTopics(ds);
    }

    /**
     * @notice Checks if a claim topic exists in the centralized registry
     * @param claimTopic The claim topic to check
     * @return exists Whether the claim topic is registered
     */
    function claimTopicExists(uint256 claimTopic) external view returns (bool exists) {
        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();
        return IdentitySystemStorage.hasClaimTopic(ds, claimTopic);
    }

    /**
     * @notice Checks if claim topic requirements are satisfied for a given sender
     * @param functionId The routing function identifier
     * @param sender Address of the sender
     * @param recipient Address of the recipient (kept for interface compatibility, not used in compliance check)
     * @return isCompliant Whether the sender satisfies claim topic requirements
     */
    function checkCompliance(
        bytes32 functionId,
        address sender,
        address recipient
    ) external view returns (bool isCompliant) {
        // If no requirements are set or function compliance is inactive, consider compliant
        if (!functionComplianceActive[functionId] || functionClaimRequirements[functionId].length == 0) {
            return true;
        }

        // Only check sender compliance
        return _validateUserClaimTopics(sender, functionClaimRequirements[functionId]);
    }

    /**
     * @notice Internal function to validate user has required claim topics
     * @param user Address to validate
     * @param requiredClaimTopics Required claim topics
     * @return isCompliant Whether the user has all required claim topics
     */
    function _validateUserClaimTopics(
        address user,
        uint256[] memory requiredClaimTopics
    ) internal view returns (bool isCompliant) {
        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();

        // Check if user has an identity registered
        if (!IdentitySystemStorage.hasIdentity(ds, user)) {
            return false;
        }

        // Check all required claim topics using the centralized storage
        for (uint256 i = 0; i < requiredClaimTopics.length; i++) {
            if (!IdentitySystemStorage._hasClaim(ds, user, requiredClaimTopics[i])) {
                return false;
            }
        }

        return true;
    }

    /**
     * @notice Routes ERC20 payment from sender to recipient, applying fee distribution.
     * @dev Uses the primary token configuration (backwards compatible).
     * @param token Address of ERC20 token being transferred.
     * @param amount Amount of tokens to route.
     * @param recipient Final recipient of the adjusted amount.
     */
    function routePaymentWithFees(
        address token,
        uint256 amount,
        address recipient
    ) external nonReentrant checkClaimTopicCompliance(ROUTE_PAYMENT_BASIC, recipient) {
        require(token != address(0), "TransferFacet: Token address cannot be zero");
        require(recipient != address(0), "TransferFacet: Recipient cannot be zero");
        require(amount > 0, "TransferFacet: Amount must be greater than zero");

        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();

        // Validate token matches configured distributionToken (original behavior)
        address configuredToken = FeeDistributorLib._getDistributionToken(ds);
        require(configuredToken != address(0), "TransferFacet: Fee distributor not initialized for ERC20");
        require(token == configuredToken, "TransferFacet: Token does not match configured distribution token");

        // Use the original primary token logic
        _routePaymentInternal(ds, token, amount, recipient, true);
    }

    /**
     * @notice Routes any supported ERC20 token payment with fee distribution.
     * @dev Uses token-specific configuration if available, falls back to primary token.
     * @param token Address of ERC20 token being transferred.
     * @param amount Amount of tokens to route.
     * @param recipient Final recipient of the adjusted amount.
     */
    function routePaymentWithFeesAnyToken(
        address token,
        uint256 amount,
        address recipient
    ) external nonReentrant checkClaimTopicCompliance(ROUTE_PAYMENT_ANY_TOKEN, recipient) {
        require(token != address(0), "TransferFacet: Token address cannot be zero");
        require(recipient != address(0), "TransferFacet: Recipient cannot be zero");
        require(amount > 0, "TransferFacet: Amount must be greater than zero");

        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();

        // Check if token has specific configuration
        bool isTokenSupported = FeeDistributorLib._isTokenSupported(ds, token);

        if (isTokenSupported) {
            // Use token-specific configuration
            _routePaymentInternal(ds, token, amount, recipient, false);
        } else {
            // Fall back to primary token validation and configuration
            address configuredToken = FeeDistributorLib._getDistributionToken(ds);
            require(configuredToken != address(0), "TransferFacet: Fee distributor not initialized");
            require(token == configuredToken, "TransferFacet: Token not supported and does not match primary token");

            // Use primary token configuration
            _routePaymentInternal(ds, token, amount, recipient, true);
        }
    }

    /**
     * @notice Routes payment for any token that has fee configuration.
     * @dev Automatically detects if token is supported, no fallback to primary token.
     * @param token Address of ERC20 token being transferred.
     * @param amount Amount of tokens to route.
     * @param recipient Final recipient of the adjusted amount.
     */
    function routePaymentWithFeesTokenOnly(
        address token,
        uint256 amount,
        address recipient
    ) external nonReentrant checkClaimTopicCompliance(ROUTE_PAYMENT_TOKEN_ONLY, recipient) {
        require(token != address(0), "TransferFacet: Token address cannot be zero");
        require(recipient != address(0), "TransferFacet: Recipient cannot be zero");
        require(amount > 0, "TransferFacet: Amount must be greater than zero");

        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();

        // Only allow tokens with specific configuration
        require(FeeDistributorLib._isTokenSupported(ds, token), "TransferFacet: Token not supported");

        _routePaymentInternal(ds, token, amount, recipient, false);
    }

    /**
     * @notice Batch route payments for multiple tokens.
     * @dev All tokens must be supported or match primary token. Protected against DOS attacks.
     * @param tokens Array of token addresses.
     * @param amounts Array of amounts corresponding to each token.
     * @param recipients Array of recipients corresponding to each token.
     */
    function batchRoutePayments(
        address[] calldata tokens,
        uint256[] calldata amounts,
        address[] calldata recipients
    ) external nonReentrant {
        require(tokens.length == amounts.length, "TransferFacet: Array length mismatch");
        require(tokens.length == recipients.length, "TransferFacet: Array length mismatch");
        require(tokens.length > 0, "TransferFacet: Empty arrays");

        // DOS protection: Limit batch size
        require(tokens.length <= MAX_BATCH_SIZE, "TransferFacet: Batch size exceeds maximum allowed");

        // Check claim topic compliance for batch operations
        if (functionComplianceActive[BATCH_ROUTE_PAYMENTS] && functionClaimRequirements[BATCH_ROUTE_PAYMENTS].length > 0) {
            require(
                _validateUserClaimTopics(msg.sender, functionClaimRequirements[BATCH_ROUTE_PAYMENTS]),
                "TransferFacet: Sender missing required claim topics for batch operations"
            );

            // Note: Only sender compliance is checked for batch operations.
            // Recipients do not need to be compliant.
        }

        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();

        uint256 totalVolume = 0;

        for (uint256 i = 0; i < tokens.length; i++) {
            require(tokens[i] != address(0), "TransferFacet: Token address cannot be zero");
            require(recipients[i] != address(0), "TransferFacet: Recipient cannot be zero");
            require(amounts[i] > 0, "TransferFacet: Amount must be greater than zero");

            // Accumulate total volume for event
            totalVolume += amounts[i];

            // Check if token has specific configuration
            bool isTokenSupported = FeeDistributorLib._isTokenSupported(ds, tokens[i]);

            if (isTokenSupported) {
                _routePaymentInternal(ds, tokens[i], amounts[i], recipients[i], false);
            } else {
                // Fall back to primary token validation
                address configuredToken = FeeDistributorLib._getDistributionToken(ds);
                require(configuredToken != address(0), "TransferFacet: Fee distributor not initialized");
                require(tokens[i] == configuredToken, "TransferFacet: Token not supported");

                _routePaymentInternal(ds, tokens[i], amounts[i], recipients[i], true);
            }
        }

        emit BatchPaymentCompleted(msg.sender, tokens.length, totalVolume);
    }

    /**
     * @notice Checks if a token is supported for routing.
     * @param token Address of the token to check.
     * @return isSupported True if token is supported (either as primary or has specific config).
     */
    function isTokenSupportedForRouting(address token) external view returns (bool isSupported) {
        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();

        // Check if token has specific configuration
        if (FeeDistributorLib._isTokenSupported(ds, token)) {
            return true;
        }

        // Check if token matches primary distribution token
        address configuredToken = FeeDistributorLib._getDistributionToken(ds);
        return (configuredToken != address(0) && token == configuredToken);
    }

    /**
     * @notice Gets all tokens supported for routing.
     * @return supportedTokens Array of supported token addresses.
     */
    function getSupportedTokensForRouting() external view returns (address[] memory supportedTokens) {
        IdentitySystemStorage.IdentitySystem storage ds = IdentitySystemStorage.diamondStorage();

        // Get tokens with specific configurations
        address[] memory tokenConfigTokens = FeeDistributorLib._getSupportedTokens(ds);

        // Get primary distribution token
        address primaryToken = FeeDistributorLib._getDistributionToken(ds);

        // Check if primary token is already in the list
        bool primaryTokenIncluded = false;
        if (primaryToken != address(0)) {
            for (uint256 i = 0; i < tokenConfigTokens.length; i++) {
                if (tokenConfigTokens[i] == primaryToken) {
                    primaryTokenIncluded = true;
                    break;
                }
            }
        }

        // Create combined array
        uint256 totalLength = tokenConfigTokens.length;
        if (primaryToken != address(0) && !primaryTokenIncluded) {
            totalLength += 1;
        }

        supportedTokens = new address[](totalLength);

        // Copy token config tokens
        for (uint256 i = 0; i < tokenConfigTokens.length; i++) {
            supportedTokens[i] = tokenConfigTokens[i];
        }

        // Add primary token if not already included
        if (primaryToken != address(0) && !primaryTokenIncluded) {
            supportedTokens[tokenConfigTokens.length] = primaryToken;
        }

        return supportedTokens;
    }

    /**
     * @notice Gets the maximum batch size allowed for batch operations.
     * @return maxSize The maximum number of transactions allowed in a single batch.
     */
    function getMaxBatchSize() external pure returns (uint256 maxSize) {
        return MAX_BATCH_SIZE;
    }

    /**
     * @notice Gets the minimum fee threshold used to prevent dust.
     * @return threshold The minimum fee threshold in basis points.
     */
    function getMinFeeThreshold() external pure returns (uint256 threshold) {
        return MIN_FEE_THRESHOLD;
    }

    /**
     * @notice Internal function to handle payment routing logic with enhanced security.
     * @param ds Diamond storage reference.
     * @param token Token address.
     * @param amount Amount to route.
     * @param recipient Final recipient.
     * @param usePrimaryConfig Whether to use primary token configuration.
     */
    function _routePaymentInternal(
        IdentitySystemStorage.IdentitySystem storage ds,
        address token,
        uint256 amount,
        address recipient,
        bool usePrimaryConfig
    ) internal {
        // Initialize ERC20 interface
        IERC20 erc20Token = IERC20(token);

        // Additional safety: Check contract balance before transfer
        uint256 contractBalanceBefore = erc20Token.balanceOf(address(this));

        // Pull tokens from sender to this contract
        erc20Token.safeTransferFrom(msg.sender, address(this), amount);

        // Verify the transfer was successful
        uint256 contractBalanceAfter = erc20Token.balanceOf(address(this));
        require(contractBalanceAfter >= contractBalanceBefore + amount, "TransferFacet: Transfer verification failed");

        uint256 adjustedAmount;
        uint256[] memory feeAmounts;
        address[] memory feeReceivers;

        if (usePrimaryConfig) {
            // Use primary token configuration
            (adjustedAmount, feeAmounts) = FeeDistributorLib._calculateAmounts(ds, amount);
            (feeReceivers, ) = FeeDistributorLib._getFeeReceivers(ds);
        } else {
            // Use token-specific configuration
            (adjustedAmount, feeAmounts) = FeeDistributorLib._calculateTokenAmounts(ds, token, amount);
            (feeReceivers, ) = FeeDistributorLib._getTokenFeeReceivers(ds, token);
        }

        require(feeReceivers.length == feeAmounts.length, "TransferFacet: Fee receiver mismatch");

        // Precision protection: Apply minimum fee threshold
        uint256 totalFeesDistributed = 0;

        // Distribute fees with dust protection
        for (uint256 i = 0; i < feeReceivers.length; i++) {
            if (feeAmounts[i] > 0) {
                // Apply minimum fee threshold to prevent dust
                if (feeAmounts[i] >= MIN_FEE_THRESHOLD) {
                    erc20Token.safeTransfer(feeReceivers[i], feeAmounts[i]);
                    totalFeesDistributed += feeAmounts[i];
                } else {
                    // Set dust fees to zero and add to adjusted amount
                    adjustedAmount += feeAmounts[i];
                    feeAmounts[i] = 0;
                }
            }
        }

        // Transfer adjusted amount to recipient
        if (adjustedAmount > 0) {
            erc20Token.safeTransfer(recipient, adjustedAmount);
        }

        // Final verification: Ensure all funds were distributed correctly
        uint256 contractBalanceFinal = erc20Token.balanceOf(address(this));
        require(contractBalanceFinal <= contractBalanceBefore, "TransferFacet: Funds not fully distributed");

        emit RoutedPayment(
            msg.sender,
            recipient,
            token,
            amount,
            adjustedAmount,
            feeReceivers,
            feeAmounts
        );
    }

    /**
     * @notice Emergency function to recover stuck tokens (only owner).
     * @dev Should only be used if tokens get stuck due to failed transfers.
     * @param token Address of the token to recover.
     * @param amount Amount to recover.
     * @param recipient Address to send recovered tokens to.
     */
    function emergencyTokenRecovery(
        address token,
        uint256 amount,
        address recipient
    ) external onlyOwner {
        require(token != address(0), "TransferFacet: Invalid token address");
        require(recipient != address(0), "TransferFacet: Invalid recipient address");
        require(amount > 0, "TransferFacet: Amount must be greater than zero");

        IERC20(token).safeTransfer(recipient, amount);
    }
