pragma solidity ^0.8.0;

import "../identity/IdentityStorage.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

library FeeDistributorLib {
    using SafeERC20 for IERC20;

    /// @notice Minimum fee threshold to prevent dust accumulation (1 wei)
    uint256 private constant MIN_FEE_THRESHOLD = 1;

    /// @notice Maximum precision scaling factor for calculations
    uint256 private constant PRECISION_FACTOR = 1e18;

    // Storage struct for Fee Distributor settings (enhanced for upgrade safety)
    struct FeeDistributorStorage {
        address[] feeReceivers;
        uint256[] feeWeights;
        uint256 totalWeightBasis;
        address distributionToken;

        //Multi-token support
        mapping(address => TokenFeeConfig) tokenConfigs;
        address[] supportedTokens;

        // Storage for upgrade safety
        bool isInitialized;
        uint256 version; // For tracking storage layout versions

        // Reserve storage slots for future upgrades (prevents storage collision)
        uint256[44] __gap; // Total of 50 slots reserved (6 used + 44 gap)
    }

    // Token-specific fee configuration
    struct TokenFeeConfig {
        address[] feeReceivers;
        uint256[] feeWeights;
        bool isActive;
        uint256 configVersion; // For tracking config changes
    }

    /**
     * @notice Initializes the Fee Distributor settings for the primary token.
     * @dev Enhanced with additional safety checks and initialization tracking.
     */
    function _initializeFeeDistributor(
        IdentitySystemStorage.IdentitySystem storage ds,
        address _distributionToken,
        uint256 _totalWeightBasis
    ) internal {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        require(!fds.isInitialized, "FeeDistributor: Already initialized");
        require(_distributionToken != address(0), "FeeDistributor: Invalid distribution token");
        require(_totalWeightBasis > 0, "FeeDistributor: Basis must be positive");

        fds.distributionToken = _distributionToken;
        fds.totalWeightBasis = _totalWeightBasis;
        fds.isInitialized = true;
        fds.version = 1; // Initial version
    }

    /**
     * @notice Re-initializes the Fee Distributor (emergency use only).
     * @dev Allows changing core settings if needed, with proper safety checks.
     */
    function _reinitializeFeeDistributor(
        IdentitySystemStorage.IdentitySystem storage ds,
        address _distributionToken,
        uint256 _totalWeightBasis
    ) internal {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        require(fds.isInitialized, "FeeDistributor: Not previously initialized");
        require(_distributionToken != address(0), "FeeDistributor: Invalid distribution token");
        require(_totalWeightBasis > 0, "FeeDistributor: Basis must be positive");

        // Clear existing primary fee receivers to prevent inconsistencies
        delete fds.feeReceivers;
        delete fds.feeWeights;

        fds.distributionToken = _distributionToken;
        fds.totalWeightBasis = _totalWeightBasis;
        fds.version += 1; // Increment version
    }

    /**
     * @notice Gets the total weight basis for fee calculations.
     * @dev NEW: Required for consistent validation across facets.
     */
    function _getTotalWeightBasis(
        IdentitySystemStorage.IdentitySystem storage ds
    ) internal view returns (uint256) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        require(fds.isInitialized, "FeeDistributor: Not initialized");
        return fds.totalWeightBasis;
    }

    /**
     * @notice Checks if the fee distributor is initialized.
     * @dev NEW: For validation in facets.
     */
    function _isInitialized(
        IdentitySystemStorage.IdentitySystem storage ds
    ) internal view returns (bool) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        return fds.isInitialized;
    }

    /**
     * @notice Sets fee receivers for the primary token.
     * @dev Enhanced with better validation and safety checks.
     */
    function _setFeeReceivers(
        IdentitySystemStorage.IdentitySystem storage ds,
        address[] memory _feeReceivers,
        uint256[] memory _feeWeights
    ) internal returns (address[] memory, uint256[] memory) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        require(fds.isInitialized, "FeeDistributor: Not initialized");
        require(_feeReceivers.length == _feeWeights.length, "FeeDistributor: Array lengths mismatch");
        require(_feeReceivers.length > 0, "FeeDistributor: Must provide at least one receiver");

        uint256 totalWeightSum = 0;
        for (uint i = 0; i < _feeReceivers.length; i++) {
            require(_feeReceivers[i] != address(0), "FeeDistributor: Invalid receiver address");
            require(_feeWeights[i] > 0, "FeeDistributor: Weight must be positive");
            totalWeightSum += _feeWeights[i];
        }
        require(totalWeightSum == fds.totalWeightBasis, "FeeDistributor: Weights must sum to basis");

        fds.feeReceivers = _feeReceivers;
        fds.feeWeights = _feeWeights;

        return (_feeReceivers, _feeWeights);
    }

    /**
     * @notice Sets fee receivers for a specific token.
     * @dev Enhanced with version tracking and duplicate prevention.
     */
    function _setTokenFeeReceivers(
        IdentitySystemStorage.IdentitySystem storage ds,
        address _token,
        address[] memory _feeReceivers,
        uint256[] memory _feeWeights
    ) internal {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        require(fds.isInitialized, "FeeDistributor: Not initialized");

        // If this is a new token, add it to supported tokens list
        if (!fds.tokenConfigs[_token].isActive) {
            // Check for duplicates before adding
            bool alreadyExists = false;
            for (uint256 i = 0; i < fds.supportedTokens.length; i++) {
                if (fds.supportedTokens[i] == _token) {
                    alreadyExists = true;
                    break;
                }
            }
            if (!alreadyExists) {
                fds.supportedTokens.push(_token);
            }
        }

        fds.tokenConfigs[_token] = TokenFeeConfig({
            feeReceivers: _feeReceivers,
            feeWeights: _feeWeights,
            isActive: true,
            configVersion: fds.version
        });
    }

    /**
     * @notice Gets fee receivers for the primary token.
     */
    function _getFeeReceivers(
        IdentitySystemStorage.IdentitySystem storage ds
    ) internal view returns (address[] memory, uint256[] memory) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        require(fds.isInitialized, "FeeDistributor: Not initialized");
        return (fds.feeReceivers, fds.feeWeights);
    }

    /**
     * @notice Gets fee receivers for a specific token.
     */
    function _getTokenFeeReceivers(
        IdentitySystemStorage.IdentitySystem storage ds,
        address _token
    ) internal view returns (address[] memory, uint256[] memory) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        TokenFeeConfig storage config = fds.tokenConfigs[_token];

        require(config.isActive, "FeeDistributor: Token not supported");
        return (config.feeReceivers, config.feeWeights);
    }

    /**
     * @notice Checks if a token is supported.
     */
    function _isTokenSupported(
        IdentitySystemStorage.IdentitySystem storage ds,
        address _token
    ) internal view returns (bool) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        return fds.tokenConfigs[_token].isActive;
    }

    /**
     * @notice Gets all supported tokens.
     * @dev Enhanced with gas optimization for large arrays.
     */
    function _getSupportedTokens(
        IdentitySystemStorage.IdentitySystem storage ds
    ) internal view returns (address[] memory) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;

        // First pass: count active tokens
        uint256 activeCount = 0;
        uint256 totalTokens = fds.supportedTokens.length;

        for (uint256 i = 0; i < totalTokens; i++) {
            if (fds.tokenConfigs[fds.supportedTokens[i]].isActive) {
                activeCount++;
            }
        }

        // Second pass: populate result array
        address[] memory activeTokens = new address[](activeCount);
        uint256 index = 0;

        for (uint256 i = 0; i < totalTokens; i++) {
            if (fds.tokenConfigs[fds.supportedTokens[i]].isActive) {
                activeTokens[index] = fds.supportedTokens[i];
                index++;
            }
        }

        return activeTokens;
    }

    /**
     * @notice Removes token fee configuration.
     * @dev Enhanced with proper cleanup and validation.
     */
    function _removeTokenFeeConfig(
        IdentitySystemStorage.IdentitySystem storage ds,
        address _token
    ) internal {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        require(fds.tokenConfigs[_token].isActive, "FeeDistributor: Token not supported");

        // Clear the configuration
        delete fds.tokenConfigs[_token].feeReceivers;
        delete fds.tokenConfigs[_token].feeWeights;
        fds.tokenConfigs[_token].isActive = false;
        fds.tokenConfigs[_token].configVersion = 0;

        // Note: We keep the token in supportedTokens array for gas efficiency
        // The _getSupportedTokens function filters out inactive ones
    }

    /**
     * @notice Calculates amounts for the primary token.
     * @dev Enhanced with precision loss protection and dust handling.
     */
    function _calculateAmounts(
        IdentitySystemStorage.IdentitySystem storage ds,
        uint256 principalAmount
    ) internal view returns (uint256 adjustedAmount, uint256[] memory feeAmounts) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        require(fds.isInitialized, "FeeDistributor: Not initialized");

        address[] memory receivers = fds.feeReceivers;
        uint256 numReceivers = receivers.length;

        if (numReceivers == 0) {
            return (principalAmount, new uint256[](0));
        }

        require(fds.totalWeightBasis > 0, "FeeDistributor: Invalid basis");
        uint256[] memory weights = fds.feeWeights;

        feeAmounts = new uint256[](numReceivers);
        uint256 totalFeeAmount = 0;
        uint256 dustRecovered = 0;

        // Calculate fees with precision protection
        for (uint i = 0; i < numReceivers; i++) {
            uint256 fee = (principalAmount * weights[i]) / fds.totalWeightBasis;

            // Apply minimum threshold to prevent dust
            if (fee > 0 && fee < MIN_FEE_THRESHOLD) {
                dustRecovered += fee;
                fee = 0;
            }

            feeAmounts[i] = fee;
            totalFeeAmount += fee;
        }

        require(totalFeeAmount <= principalAmount, "FeeDistributor: Total fees exceed principal");
        adjustedAmount = principalAmount - totalFeeAmount + dustRecovered; // Add dust back to principal

        return (adjustedAmount, feeAmounts);
    }

    /**
     * @notice Calculates amounts for a specific token.
     */
    function _calculateTokenAmounts(
        IdentitySystemStorage.IdentitySystem storage ds,
        address _token,
        uint256 principalAmount
    ) internal view returns (uint256 adjustedAmount, uint256[] memory feeAmounts) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        TokenFeeConfig storage config = fds.tokenConfigs[_token];

        require(config.isActive, "FeeDistributor: Token not supported");
        require(fds.isInitialized, "FeeDistributor: Not initialized");

        uint256 numReceivers = config.feeReceivers.length;
        if (numReceivers == 0) {
            return (principalAmount, new uint256[](0));
        }

        feeAmounts = new uint256[](numReceivers);
        uint256 totalFeeAmount = 0;
        uint256 dustRecovered = 0;

        // Use the configured basis instead of hardcoded 10000
        uint256 basis = fds.totalWeightBasis;
        require(basis > 0, "FeeDistributor: Invalid basis");

        // Calculate fees with precision protection
        for (uint i = 0; i < numReceivers; i++) {
            uint256 fee = (principalAmount * config.feeWeights[i]) / basis;

            // Apply minimum threshold to prevent dust
            if (fee > 0 && fee < MIN_FEE_THRESHOLD) {
                dustRecovered += fee;
                fee = 0;
            }

            feeAmounts[i] = fee;
            totalFeeAmount += fee;
        }

        require(totalFeeAmount <= principalAmount, "FeeDistributor: Total fees exceed principal");
        adjustedAmount = principalAmount - totalFeeAmount + dustRecovered; // Add dust back to principal

        return (adjustedAmount, feeAmounts);
    }

    /**
     * @notice Gets the primary distribution token address.
     */
    function _getDistributionToken(
        IdentitySystemStorage.IdentitySystem storage ds
    ) internal view returns (address) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        return fds.distributionToken;
    }

    /**
     * @notice Distributes amounts using primary token configuration.
     * @dev Enhanced with better error handling and balance verification.
     */
    function _distributeAmounts(
        IdentitySystemStorage.IdentitySystem storage ds,
        address self,
        address principalAmountReceiver,
        uint256 _principalAmount
    ) internal returns (
        address adjustedAmountReceiver_,
        uint256 adjustedAmount_,
        address[] memory feeReceivers_,
        uint256[] memory feeAmounts_
    ) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        require(fds.isInitialized, "FeeDistributor: Not initialized");
        require(principalAmountReceiver != address(0), "FeeDistributor: Invalid principal receiver");
        require(_principalAmount > 0, "FeeDistributor: Amount must be positive");

        (uint256 adjustedAmount, uint256[] memory feeAmounts) = _calculateAmounts(ds, _principalAmount);
        address[] memory receivers = fds.feeReceivers;

        bool isNative = fds.distributionToken == address(0);

        if (isNative) {
            require(self.balance >= _principalAmount, "FeeDistributor: Insufficient native balance");

            // Distribute fees with error handling
            for (uint i = 0; i < receivers.length; i++) {
                if (feeAmounts[i] > 0) {
                    (bool success, ) = payable(receivers[i]).call{value: feeAmounts[i]}("");
                    require(success, "FeeDistributor: Native fee transfer failed");
                }
            }

            // Transfer principal amount
            if (adjustedAmount > 0) {
                (bool success, ) = payable(principalAmountReceiver).call{value: adjustedAmount}("");
                require(success, "FeeDistributor: Native principal transfer failed");
            }
        } else {
            IERC20 token = IERC20(fds.distributionToken);
            uint256 contractBalance = token.balanceOf(self);
            require(contractBalance >= _principalAmount, "FeeDistributor: Insufficient token balance");

            // Distribute fees
            for (uint i = 0; i < receivers.length; i++) {
                if (feeAmounts[i] > 0) {
                    token.safeTransfer(receivers[i], feeAmounts[i]);
                }
            }

            // Transfer principal amount
            if (adjustedAmount > 0) {
                token.safeTransfer(principalAmountReceiver, adjustedAmount);
            }
        }

        return (principalAmountReceiver, adjustedAmount, receivers, feeAmounts);
    }

    /**
     * @notice Distributes amounts for a specific token.
     */
    function _distributeTokenAmounts(
        IdentitySystemStorage.IdentitySystem storage ds,
        address _token,
        address self,
        address principalAmountReceiver,
        uint256 _principalAmount
    ) internal returns (
        address adjustedAmountReceiver_,
        uint256 adjustedAmount_,
        address[] memory feeReceivers_,
        uint256[] memory feeAmounts_
    ) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        TokenFeeConfig storage config = fds.tokenConfigs[_token];

        require(fds.isInitialized, "FeeDistributor: Not initialized");
        require(config.isActive, "FeeDistributor: Token not supported");
        require(principalAmountReceiver != address(0), "FeeDistributor: Invalid principal receiver");
        require(_principalAmount > 0, "FeeDistributor: Amount must be positive");

        (uint256 adjustedAmount, uint256[] memory feeAmounts) = _calculateTokenAmounts(ds, _token, _principalAmount);

        IERC20 token = IERC20(_token);
        uint256 contractBalance = token.balanceOf(self);
        require(contractBalance >= _principalAmount, "FeeDistributor: Insufficient token balance");

        // Distribute fees
        for (uint i = 0; i < config.feeReceivers.length; i++) {
            if (feeAmounts[i] > 0) {
                token.safeTransfer(config.feeReceivers[i], feeAmounts[i]);
            }
        }

        // Transfer principal amount
        if (adjustedAmount > 0) {
            token.safeTransfer(principalAmountReceiver, adjustedAmount);
        }

        return (principalAmountReceiver, adjustedAmount, config.feeReceivers, feeAmounts);
    }

    /**
     * @notice Gets the current storage version.
     */
    function _getStorageVersion(
        IdentitySystemStorage.IdentitySystem storage ds
    ) internal view returns (uint256) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        return fds.version;
    }

    /**
     * @notice Gets comprehensive fee distributor state.
     */
    function _getDistributorState(
        IdentitySystemStorage.IdentitySystem storage ds
    ) internal view returns (
        bool initialized,
        address distributionToken,
        uint256 totalWeightBasis,
        uint256 version,
        uint256 supportedTokenCount
    ) {
        FeeDistributorStorage storage fds = ds.feeDistributorStorage;
        return (
            fds.isInitialized,
            fds.distributionToken,
            fds.totalWeightBasis,
            fds.version,
            fds.supportedTokens.length
        );
    }
